import React from 'react';
import FoodCard from '../shared/FoodCard';

const items = [
  { id: 1, name: 'Burger', price: 10 },
  { id: 2, name: 'Fries', price: 5 }
];

export default function Menu() {
  return (
    <div>
      <h1>Menu</h1>
      {items.map(item => (
        <FoodCard key={item.id} item={item} />
      ))}
    </div>
  );
}
